class User:
    def __init__(self, name, tier):
        self.name = name
        self.tier = tier


class DiscountCode:
    def __init__(self, code, description, admin_only=False, user_tiers=None):
        self.code = code
        self.description = description
        self.admin_only = admin_only
        self.user_tiers = user_tiers if user_tiers else []


class Order:
    def __init__(self, cart_items, discount_code=None):
        self.cart_items = cart_items
        self.discount_code = discount_code
        self.tax_amount = 0
        self.total_amount = 0


def validate_cart_items(cart_items):
    for item in cart_items:
        if not isinstance(item, dict) or 'name' not in item or 'price' not in item:
            return False
    return True


def apply_discount_code(order, discount_code):
    if order.discount_code.code == discount_code.code:
        if (discount_code.admin_only and User('admin', 'tier1') != order.user) or (User('admin', 'tier1').tier not in discount_code.user_tiers):
            return False
        order.total_amount *= 0.9
    return True


def calculate_tax(order):
    order.tax_amount = order.total_amount * 0.08
    order.total_amount += order.tax_amount
    return True


def process_payment(order, payment_method):
    if payment_method == 'credit_card':
        print(f'Payment processed successfully using {payment_method}')
    else:
        return False


def create_order_record(order):
    print(f'Order record created for user: {order.user.name}, items: {[item["name"] for item in order.cart_items]}, total amount: {order.total_amount}')


def checkout_process(cart_items, discount_code=None, payment_method='credit_card', user=User('user1', 'tier2')):
    if not validate_cart_items(cart_items):
        return False

    order = Order(cart_items, discount_code)
    order.user = user

    if not apply_discount_code(order, DiscountCode('DISCOUNT10', '10% off', admin_only=False)):
        return False

    calculate_tax(order)

    process_payment(order, payment_method)

    create_order_record(order)
    return True


cart_items = [{'name': 'Item1', 'price': 100}, {'name': 'Item2', 'price': 200}]
